<script>
 import{onMount}from'svelte';import{Bell,Sun,Search,CheckCheck,Trash2,RefreshCw}from'lucide-svelte';let briefing=$state(null),memories=$state([]),notifications=$state([]),query=$state('current goals projects tasks and preferences'),loading=$state(true),error=$state('');onMount(load);
 async function load(){loading=true;error='';try{const[b,n]=await Promise.all([fetch(`/api/intelligence/briefing?q=${encodeURIComponent(query)}`).then(r=>r.json()),fetch('/api/notifications').then(r=>r.json())]);briefing=b.briefing;memories=b.relevantMemories??[];notifications=n.notifications??[]}catch(e){error=e instanceof Error?e.message:String(e)}loading=false}
 async function markRead(){await fetch('/api/notifications',{method:'PATCH',headers:{'content-type':'application/json'},body:'{}'});await load()}async function clear(){await fetch('/api/notifications',{method:'DELETE'});await load()}
</script>
<svelte:head><title>Daily Briefing · J.A.R.V.I.S.</title></svelte:head><div class="page"><header><Sun size={22}/><div><h1>Daily Briefing</h1><p>Local planning, relevant memory, and automation notifications.</p></div><button onclick={load} disabled={loading}><RefreshCw size={14}/>Refresh</button></header>{#if error}<p class="error">{error}</p>{/if}{#if briefing}<section class="hero"><span>{briefing.date}</span><h2>{briefing.summary}</h2>{#each briefing.recommendations as item(item)}<p>→ {item}</p>{/each}<div><b>{briefing.taskIds.length}</b> tasks <b>{briefing.eventIds.length}</b> events</div></section>{/if}<section class="columns"><article><div class="section-head"><h2><Search size={15}/>Relevant memory</h2></div><form onsubmit={(event)=>{event.preventDefault();load()}}><input bind:value={query} placeholder="What context matters today?"/><button aria-label="Search"><Search size={14}/></button></form>{#each memories as memory(memory.id)}<div class="memory"><strong>{memory.category}</strong><p>{memory.content}</p><small>Relevance {Math.round(memory.relevance*100)}%</small></div>{/each}{#if !memories.length}<p class="empty">No relevant memories yet.</p>{/if}</article><article><div class="section-head"><h2><Bell size={15}/>Notifications</h2><span><button onclick={markRead} aria-label="Mark all read"><CheckCheck size={14}/></button><button onclick={clear} aria-label="Clear notifications"><Trash2 size={14}/></button></span></div>{#each notifications as item(item.id)}<div class:unread={!item.readAt} class="notification"><strong>{item.title}</strong><p>{item.message}</p><small>{new Date(item.createdAt).toLocaleString()} · {item.source}</small></div>{/each}{#if !notifications.length}<p class="empty">No notifications.</p>{/if}</article></section></div>
<style>.page{padding:var(--space-6);display:grid;gap:var(--space-5);max-width:1150px}header{display:flex;align-items:center;gap:.8rem}header div{flex:1}h1{margin:0;font-size:var(--text-2xl)}header p,.empty{margin:.25rem 0;color:var(--text-secondary);font-size:var(--text-sm)}button,input{border:1px solid var(--surface-border);background:var(--surface-card);color:var(--text-primary);border-radius:var(--radius-md);padding:.6rem;cursor:pointer}header button{display:flex;gap:.35rem;align-items:center}.hero{border:1px solid var(--surface-border);border-radius:var(--radius-lg);background:var(--surface-card);padding:1.2rem}.hero>span,.hero p,.hero div{font-size:var(--text-xs);color:var(--text-secondary)}.hero h2{font-size:var(--text-xl);margin:.45rem 0}.hero b{font-size:var(--text-lg);color:var(--text-primary);margin-right:.25rem}.columns{display:grid;grid-template-columns:1fr 1fr;gap:.8rem}.columns>article{border:1px solid var(--surface-border);border-radius:var(--radius-lg);background:var(--surface-card);padding:1rem}.section-head{display:flex;justify-content:space-between;align-items:center}.section-head h2{display:flex;align-items:center;gap:.4rem;font-size:var(--text-sm);margin:0}.section-head button{border:0;padding:.35rem}form{display:flex;margin:.8rem 0}form input{flex:1}.memory,.notification{border-top:1px solid var(--surface-border-subtle);padding:.7rem 0}.memory strong,.notification strong{font-size:var(--text-xs)}.memory p,.notification p{font-size:var(--text-xs);color:var(--text-secondary);margin:.3rem 0}.memory small,.notification small{font-size:10px;color:var(--text-tertiary)}.notification.unread{border-left:2px solid var(--color-accent-500);padding-left:.6rem}.error{color:var(--color-error-500)}@media(max-width:750px){.page{padding:var(--space-4)}.columns{grid-template-columns:1fr}header{align-items:flex-start;flex-wrap:wrap}}</style>
